  describe('Prop Defaults', () => {
    it('should declare prop "accept" with type "option String"', () => {
      const prop = { name: 'accept', type: 'option String' };
      expect(prop.name).toBe('accept');
      expect(prop.type).toBeTruthy();
    });

    it('should declare prop "multiple" with type "Bool"', () => {
      const prop = { name: 'multiple', type: 'Bool', defaultValue: "true" };
      expect(prop.name).toBe('multiple');
      expect(prop.type).toBeTruthy();
    });

    it('should default "multiple" to "true"', () => {
      expect("true").toBe("true");
    });

    it('should declare prop "maxSize" with type "option Int"', () => {
      const prop = { name: 'maxSize', type: 'option Int' };
      expect(prop.name).toBe('maxSize');
      expect(prop.type).toBeTruthy();
    });

    it('should declare prop "maxFiles" with type "option Int"', () => {
      const prop = { name: 'maxFiles', type: 'option Int' };
      expect(prop.name).toBe('maxFiles');
      expect(prop.type).toBeTruthy();
    });

    it('should declare prop "disabled" with type "Bool"', () => {
      const prop = { name: 'disabled', type: 'Bool', defaultValue: "false" };
      expect(prop.name).toBe('disabled');
      expect(prop.type).toBeTruthy();
    });

    it('should default "disabled" to "false"', () => {
      expect("false").toBe("false");
    });

    it('should declare prop "name" with type "option String"', () => {
      const prop = { name: 'name', type: 'option String' };
      expect(prop.name).toBe('name');
      expect(prop.type).toBeTruthy();
    });

  });

  describe('Anatomy Parts', () => {
    it('should declare all anatomy parts', () => {
      const parts = ["root","dropzone","dropzoneIcon","dropzoneLabel","input","fileList","fileItem","fileIcon","fileName","fileSize","fileProgress","fileRemove","fileError"];
      expect(parts.length).toBe(13);
      expect(parts).toContain('root');
      expect(parts).toContain('dropzone');
      expect(parts).toContain('dropzoneIcon');
      expect(parts).toContain('dropzoneLabel');
      expect(parts).toContain('input');
      expect(parts).toContain('fileList');
      expect(parts).toContain('fileItem');
      expect(parts).toContain('fileIcon');
      expect(parts).toContain('fileName');
      expect(parts).toContain('fileSize');
      expect(parts).toContain('fileProgress');
      expect(parts).toContain('fileRemove');
      expect(parts).toContain('fileError');
    });

    it('should assign semantic roles to anatomy parts', () => {
      expect('container').toBeTruthy(); // root: container
      expect('container').toBeTruthy(); // dropzone: container
      expect('container').toBeTruthy(); // dropzoneIcon: container
      expect('text').toBeTruthy(); // dropzoneLabel: text
      expect('action').toBeTruthy(); // input: action
      expect('container').toBeTruthy(); // fileList: container
      expect('container').toBeTruthy(); // fileItem: container
      expect('container').toBeTruthy(); // fileIcon: container
      expect('text').toBeTruthy(); // fileName: text
      expect('text').toBeTruthy(); // fileSize: text
      expect('widget').toBeTruthy(); // fileProgress: widget
      expect('action').toBeTruthy(); // fileRemove: action
      expect('text').toBeTruthy(); // fileError: text
    });

  });

